-- Products table
DROP TABLE IF EXISTS products;
CREATE TABLE products (id, tcin, title, brand, price, retail_price, original_price, has_promotion, savings_amount, discount_percentage, max_discount, is_clearance, material, sales_count, delivery_date, is_new, rating, review_count, secondary_ratings, color_summary, color, size_summary, bullet_points, image_url, product_url, item_type, date_added, date_updated, first_seen_date);

-- Unique products table (deduplicated)
DROP TABLE IF EXISTS unique_products;
CREATE TABLE unique_products (tcin, title, color_summary, size_summary, retail_price, item_type, image_url, brand, product_url, rating, review_count);

-- Daily new arrivals table
DROP TABLE IF EXISTS daily_new_arrivals;
CREATE TABLE daily_new_arrivals (id, tcin, title, brand, price, image_url, product_url, date_detected, is_processed, item_type);
